import { describe, expect, it } from 'vitest';

import {
  buildOpenAiServerMeshPipeline,
  parseOpenAiServerLayerRanges,
  resolveOpenAiServerMeshConfig,
} from '../openai-server-mesh';

describe('openai-server mesh topology config', () => {
  it('stays on the single fat-station path when mesh URLs are absent', () => {
    expect(resolveOpenAiServerMeshConfig({})).toBeNull();
  });

  it('parses explicit layer ranges', () => {
    expect(parseOpenAiServerLayerRanges('0:14,14:28')).toEqual([
      [0, 14],
      [14, 28],
    ]);
    expect(parseOpenAiServerLayerRanges('0-14,14-28')).toEqual([
      [0, 14],
      [14, 28],
    ]);
  });

  it('requires station URLs and layer ranges to match', () => {
    expect(() =>
      resolveOpenAiServerMeshConfig({
        MESH_STATION_URLS: 'https://node1.example,https://node2.example',
        MESH_LAYER_RANGES: '0:28',
        MESH_HIDDEN_DIM: '3584',
      }),
    ).toThrow(/MESH_STATION_URLS has 2 entries/);
  });

  it('builds a pipeline with cobordism topology metadata', () => {
    const config = resolveOpenAiServerMeshConfig({
      MESH_STATION_URLS: 'https://node1.example,https://node2.example',
      MESH_LAYER_RANGES: '0:14,14:28',
      MESH_HIDDEN_DIM: '3584',
      MESH_VOCAB_SIZE: '152064',
      MESH_COBORDISM_URLS: 'https://s0.example,https://s1.example',
      MESH_COBORDISM_RANGES: '0:76032,76032:152064',
    });
    expect(config).not.toBeNull();
    if (!config) throw new Error('expected mesh config');

    const built = buildOpenAiServerMeshPipeline(config, { stopTokens: [151645] });

    expect(built.topology).toEqual({
      kind: 'mesh',
      stationCount: 2,
      cobordismShardCount: 2,
      layerRanges: [
        [0, 14],
        [14, 28],
      ],
      stationUrls: ['https://node1.example', 'https://node2.example'],
    });
  });
});
